"use client";

import { useEffect, useRef, useState } from "react";



function FooterCanvas({ text }) {
    const canvasRef = useRef(null);
    const mouseRef = useRef(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        
        const parent = canvas.parentElement;
        if (!parent) return;

        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        let particles = [];
        let animationFrameId = 0;
        let isInitialized = false;

        const init = () => {
            const rect = parent.getBoundingClientRect();
            const width = rect.width;
            const height = rect.height;
            if (width === 0 || height === 0) return;

            const dpr = window.devicePixelRatio || 1;
            const w = Math.floor(width);
            const h = Math.floor(height);

            canvas.width = w * dpr;
            canvas.height = h * dpr;
            canvas.style.width = `${w}px`;
            canvas.style.height = `${h}px`;
            ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

            const offscreenCanvas = document.createElement("canvas");
            const offscreenCtx = offscreenCanvas.getContext("2d");
            if (!offscreenCtx) return;

            offscreenCanvas.width = w;
            offscreenCanvas.height = h;
            offscreenCtx.fillStyle = "#ffffff";
            offscreenCtx.textAlign = "left";
            offscreenCtx.textBaseline = "top";

            const parts = text.replace(/\.$/, "").split(" Lab");
            const lines = parts.length === 2 ? [parts[0], "Lab."] : [text];
            const fontSize = Math.min(78, w / 7.6);
            const lineHeight = 1.08 * fontSize;

            offscreenCtx.font = `500 ${fontSize}px "ABC Favorit Mono", monospace`;
            lines.forEach((line, index) => {
                offscreenCtx.fillText(line, 0, index * lineHeight);
            });

            const imgData = offscreenCtx.getImageData(0, 0, w, h).data;
            const step = Math.max(3, Math.floor(w / 170));
            const newParticles = [];

            for (let y = 0; y < h; y += step) {
                for (let x = 0; x < w; x += step) {
                    const alphaIdx = (y * w + x) * 4 + 3;
                    if (imgData[alphaIdx] > 80) {
                        newParticles.push({
                            x: x + (Math.random() - 0.5) * 10,
                            y: y + (Math.random() - 0.5) * 10,
                            targetX: x,
                            targetY: y,
                            size: Math.max(1.4, 0.42 * step)
                        });
                    }
                }
            }
            particles = newParticles;
            isInitialized = true;
        };

        const animate = () => {
            const rect = parent.getBoundingClientRect();
            const width = rect.width;
            const height = rect.height;
            if (width > 0 && height > 0) {
                ctx.clearRect(0, 0, width, height);
                ctx.fillStyle = "rgba(255, 255, 255, 0.32)";

                particles.forEach((p) => {
                    let forceX = 0;
                    let forceY = 0;
                    const mouse = mouseRef.current;

                    if (mouse) {
                        const dx = p.targetX - mouse.x;
                        const dy = p.targetY - mouse.y;
                        const dist = Math.hypot(dx, dy);
                        if (dist < 82 && dist > 0) {
                            const strength = (1 - dist / 82) * 28;
                            forceX = (dx / dist) * strength;
                            forceY = (dy / dist) * strength;
                        }
                    }

                    p.x += (p.targetX + forceX - p.x) * 0.16;
                    p.y += (p.targetY + forceY - p.y) * 0.16;
                    ctx.globalAlpha = mouseRef.current ? 1 : 0.86;
                    ctx.fillRect(p.x, p.y, p.size, p.size);
                });

                ctx.globalAlpha = 1;
            }
            animationFrameId = window.requestAnimationFrame(animate);
        };

        // ResizeObserver to handle dimensions changes and trigger init cleanly
        const resizeObserver = new ResizeObserver((entries) => {
            for (let entry of entries) {
                const { width, height } = entry.contentRect;
                if (width > 0 && height > 0) {
                    init();
                }
            }
        });
        resizeObserver.observe(parent);

        // Ensure init runs when fonts are loaded
        if (typeof document !== 'undefined' && document.fonts) {
            document.fonts.ready.then(() => {
                init();
            });
        }

        init();
        animate();

        return () => {
            resizeObserver.disconnect();
            window.cancelAnimationFrame(animationFrameId);
        };
    }, [text]);

    return (
        <div className="relative hidden h-51.25 w-full max-w-166.5 md:block" aria-label={text}>
            <canvas
                ref={canvasRef}
                className="absolute inset-0 cursor-crosshair"
                onMouseMove={(e) => {
                    const rect = e.currentTarget.getBoundingClientRect();
                    mouseRef.current = {
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top
                    };
                }}
                onMouseLeave={() => {
                    mouseRef.current = null;
                }}
            />
            <span className="sr-only">{text}</span>
        </div>
    );
}


